LAYER
	NAME "lotes_con_sin_ficha"
	TYPE point
	STATUS on
	DATA "geom FROM (SELECT gid, cod_sector, CASE WHEN con_ficha IS NULL THEN 0 ELSE con_ficha END AS con_ficha, CASE WHEN sin_ficha IS NULL THEN 0 ELSE sin_ficha END AS sin_ficha, geom FROM public.v_lotes_con_sin_ficha) as mpu using unique gid using srid=4326"
	INCLUDE "configuracion/postgresql_mpu.map"
	CLASSITEM "gid"
	PROJECTION
	"init=epsg:4326"
	END
	METADATA
		"layer_encoding" "Latin1"
		"wfs_encoding" "Latin1"
		"queryable" "true"
		"wfs_abstract" "Lotes con ficha y sin ficha || Municipalidad Provincial de Urubamba - Cusco :: Perú"
		"wfs_title" "Lotes con ficha y sin ficha"
		"wfs_credit" "MPU"
		"wfs_srs" "EPSG:4326"
		"gml_include_items" "all"
		"gml_featureid" "gid"
		#"gml_nume_doc_type" "Character"
		"wfs_getfeature_formatlist" "OGRGML,SHAPE-ZIP,CSV,geojson"
		#"wfs_additional_files_in_output" "lotes.pdf,lotes.lyr"
	END
	CLASS
		NAME "Lotes"
		STYLE
			COLOR -1 -1 -1
			OUTLINECOLOR 100 107 99
			WIDTH 1
		END
	END
END # Layer